@app.route("/internal/tokens", methods=["POST"])
def create_token():
    data = request.get_json(silent=True) or {}
    token = data.get("token")
    subject = data.get("subject")
    scope = data.get("scope", "")
    client_id = data.get("client_id")
    expires_at = data.get("expires_at")

    if not token:
        return jsonify({"error": "token is required"}), 400

    db = get_db()
    try:
        db.execute(
            """
            INSERT INTO access_tokens (token, subject, scope, client_id, expires_at, revoked)
            VALUES (?, ?, ?, ?, ?, 0)
            """,
            (token, subject, scope, client_id, expires_at),
        )
        db.commit()
    except sqlite3.IntegrityError:
        return jsonify({"error": "token already exists"}), 409

    return (
        jsonify(
            {
                "token": token,
                "subject": subject,
                "scope": scope.split() if scope else [],
                "client_id": client_id,
                "expires_at": expires_at,
            }
        ),
        201,
    )


@app.route("/internal/tokens/<token>/revoke", methods=["POST"])
def revoke_token(token):
    db = get_db()
    result = db.execute(
        "UPDATE access_tokens SET revoked = 1 WHERE token = ?",
        (token,),
    )
    db.commit()

    if result.rowcount == 0:
        return jsonify({"error": "token not found"}), 404

    return jsonify({"revoked": True, "token": token})


